}
 #testimonial .widget:nth-child(2), #testimonial .widget:nth-child(4){
}
 .testi-avatar{
    float:left;
    width:45px;
    height:45px;
    overflow:hidden;
border-radius:50%;
    margin:0 15px 0 0
}
 .testi-avatar img{
    display:block;
    width:100%;
    height:100%;
    object-fit:cover;
    color:transparent;
    margin:0
}
 .testi-info{
    overflow:hidden
}
 .testi-title{
    font-size:20px;
    color:$(title.color);
    font-weight:700;
    margin:0 0 3px
}
 .testi-meta{
    font-size:12px;
