body.script:
//
jQuery(function ($) {

  // ----- Main menu: detect submenus, mark mega-menus (label starts with '_'),
  //       and add .has-sub class so the CSS arrow shows up.
  $('#main-menu').each(function () {
    var $menu = $(this);
    $menu.find('ul#main-menu-nav > li').each(function () {
      var $li = $(this);
      $li.find('> ul').addClass('sub-menu');
      $li.find('> ul > li > a').each(function () {
        var label = $(this).text();
        if (label.charAt(0) === '_') {
          // '_'-prefixed labels are nested mega-menu items
          $(this).text(label.replace('_', ''));
          $(this).parent().appendTo($li.children('.sub-menu'));
        }
      });
    });
    $menu.find('ul li ul').parent('li').addClass('has-sub');
    $menu.find('.widget').addClass('show-menu');
  });

  // Clone desktop nav into mobile menu container and add submenu toggles.
  $('#main-menu-nav').clone().appendTo('.mobile-menu');
  $('.mobile-menu .has-sub').append('<div class="submenu-toggle"/>');

  // Rewrite mega-menu top-level items to category search URLs.
  $('.mobile-menu ul > li a').each(function () {
    var classes = $(this).attr('class') || '';
    if (classes.match(/mega-menu/)) {
      var label = $(this).text();
      $(this).attr('href', '/search/label/' + label + '?&max-results=' + postPerPage);
    }
  });

  // ----- UI toggles -----
  $('.mobile-menu-toggle').on('click', function () {
    $('body').toggleClass('nav-active');
  });

  $('.mobile-menu ul li .submenu-toggle').on('click', function (e) {
    e.preventDefault();
    var $parent = $(this).parent();
    if (!$parent.hasClass('show')) {
      $parent.addClass('show').children('.sub-menu').slideToggle(170);
    } else {
      $parent.removeClass('show').find('> .sub-menu').slideToggle(170);
    }
  });

  $('.social-toggle').on('click', function () {
    $('body').toggleClass('social-active');
    $('#social-menu').fadeToggle(170);
  });

  $('.show-search').on('click', function () {
    $('#nav-search, .mobile-search-form').fadeIn(250).find('input').focus();
  });
  $('.hide-search').on('click', function () {
    $('#nav-search, .mobile-search-form').fadeOut(250).find('input').blur();
  });

  // ----- Label/tag links: append max-results so paginated label pages work.
  $('.Label a, a.b-label, a.post-tag').attr('href', function (_, href) {
    return href.replace(href, href + '?&max-results=' + postPerPage);
  });

  // ----- Author description links open in new tab.
  $('.author-description a').each(function () {
    $(this).attr('target', '_blank');
  });

  // ----- Counter widget animation: count from 0 up to the rendered number
  //       when the element scrolls into view. Replaces the counterUp +
  //       Waypoints plugins (both abandoned/niche) with platform APIs.
  document.querySelectorAll('.counter-info .counter-title').forEach(function (el) {
    var raw = el.textContent.trim();
    var target = parseFloat(raw.replace(/[^0-9.\-]/g, ''));
    if (!isFinite(target)) return;
    var hasComma = /,/.test(raw);
    var format = function (n) {
      var s = String(Math.round(n));
      return hasComma ? s.replace(/\B(?=(\d{3})+(?!\d))/g, ',') : s;
    };
    el.textContent = format(0);
    var observer = new IntersectionObserver(function (entries) {
      entries.forEach(function (entry) {
        if (!entry.isIntersecting) return;
        observer.disconnect();
        var duration = 3000, started = null;
        requestAnimationFrame(function tick(now) {
          if (started === null) started = now;
          var p = Math.min((now - started) / duration, 1);
          var eased = 1 - Math.pow(1 - p, 3);  // ease-out cubic
          el.textContent = format(eased * target);
          if (p < 1) requestAnimationFrame(tick);
        });
      });
    }, { threshold: 0.5 });
    observer.observe(el);
  });

  // ----- Per-post sidebar position markers: a <strike>left-sidebar</strike>,
  //       <strike>right-sidebar</strike>, or <strike>full-width</strike> inside
  //       a post body swaps the wrapper layout for that post.
  $('.post-body strike').each(function () {
    var $el = $(this);
    var marker = $el.text();
    if (marker.match('left-sidebar')) {
      $el.replaceWith('<style>.item #main-wrapper{float:right}.item #sidebar-wrapper{float:left}</style>');
    } else if (marker.match('right-sidebar')) {
      $el.replaceWith('<style>.item #main-wrapper{float:left}.item #sidebar-wrapper{float:right}</style>');
    } else if (marker.match('full-width')) {
      $el.replaceWith('<style>.item #main-wrapper{width:100%}.item #sidebar-wrapper{display:none}</style>');
    }
  });

  // ----- Sticky sidebar: posts follow as you scroll. Gated on `fixedSidebar`
  //       (defined in the Global Variables script above). Hand-rolled
  //       replacement for theiaStickySidebar — keeps the existing float
  //       layout and just shifts the sidebar with `top:` during scroll, so it
  //       stays in its column without needing a flex/grid container.
  if (typeof fixedSidebar !== 'undefined' && fixedSidebar === true) {
    var sidebar = document.getElementById('sidebar-wrapper');
    var main = document.getElementById('main-wrapper');
    if (sidebar && main) {
      var marginTop = 30, marginBottom = 30;
      sidebar.style.position = 'relative';
      var rafPending = false;
      var update = function () {
        rafPending = false;
        // Only stick when the sidebar is shorter than the main column —
        // otherwise there's nothing to gain from following the scroll.
        if (sidebar.offsetHeight >= main.offsetHeight) {
          sidebar.style.top = '';
          return;
        }
        var mainTop = main.getBoundingClientRect().top + window.scrollY;
        var maxOffset = main.offsetHeight - sidebar.offsetHeight - marginBottom;
        var scrolled = window.scrollY + marginTop - mainTop;
        sidebar.style.top = Math.max(0, Math.min(scrolled, maxOffset)) + 'px';
      };
      var schedule = function () {
        if (rafPending) return;
        rafPending = true;
        requestAnimationFrame(update);
      };
      window.addEventListener('scroll', schedule, { passive: true });
      window.addEventListener('resize', schedule);
      update();
    }
  }

  // ----- Back to top: show after scrolling 100px, click to animate to top.
  $('.back-top').each(function () {
    var $btn = $(this);
    $(window).on('scroll', function () {
      if ($(this).scrollTop() >= 100) $btn.fadeIn(250);
      else $btn.fadeOut(250);
    });
    $btn.on('click', function () {
      $('html, body').animate({ scrollTop: 0 }, 500);
    });
  });

  // ----- Helper: HTML-escape strings inserted into generated markup.
  function esc(s) {
    return String(s == null ? '' : s).replace(/[&<>"']/g, function (c) {
      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c];
    });
  }

  // ----- Related posts: fetch a few posts sharing the post's first label via
  //       Blogger's JSON feed and render them under .related-ready. Uses
  //       fetch() instead of JSONP so there's no global callback pollution.
  $('.related-ready').each(function () {
    var $container = $(this);
    var label = $container.find('.related-tag').data('label');
    var count = 3;
    var feedUrl = (label && label !== 'random')
      ? '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json&max-results=' + (count + 1)
      : '/feeds/posts/default?alt=json&max-results=' + count + '&orderby=published';
    fetch(feedUrl).then(function (r) { return r.json(); }).then(function (data) {
      var entries = (data.feed && data.feed.entry) || [];
      var currentPath = location.pathname;
      var items = [];
      for (var i = 0; i < entries.length && items.length < count; i++) {
        var entry = entries[i];
        var alt = (entry.link || []).filter(function (l) { return l.rel === 'alternate'; })[0];
        if (!alt) continue;
        if (alt.href.indexOf(currentPath) !== -1) continue;
        var thumb = (entry['media$thumbnail'] && entry['media$thumbnail'].url) || (typeof noThumbnail !== 'undefined' ? noThumbnail : '');
        // Bump default 72px thumbnail up to a usable size for the 120px block.
        thumb = thumb.replace(/\/s72-c\//, '/w320-h180-p-k-no-nu/');
        items.push({
          url: alt.href,
          title: (entry.title && entry.title.$t) || '',
          thumb: thumb,
        });
      }
      if (!items.length) { $container.html(''); return; }
      $container.html(
        '<ul class="related-posts">' +
        items.map(function (it) {
          return '<li class="related-item">' +
                   '<a class="post-image-link" href="' + esc(it.url) + '">' +
                     '<img class="post-thumb" src="' + esc(it.thumb) + '" alt="' + esc(it.title) + '"/>' +
                   '</a>' +
                   '<h4 class="post-title"><a href="' + esc(it.url) + '">' + esc(it.title) + '</a></h4>' +
                 '</li>';
        }).join('') +
        '</ul>'
      );
    }).catch(function () { $container.html(''); });
  });

  // ----- Post navigation: fetch the prev/next post pages and extract their
  //       titles so the nav links can show what's coming/going. Uses
  //       DOMParser (no script execution) and only sets .text() — no HTML
  //       injection — so the fetched HTML can't introduce DOM nodes.
  $('.post-nav').each(function () {
    [
      { linkSel: '.prev-post-link', target: '.post-prev a .post-nav-inner p' },
      { linkSel: '.next-post-link', target: '.post-next a .post-nav-inner p' },
    ].forEach(function (cfg) {
      var href = $(cfg.linkSel).attr('href');
      if (!href) return;
      fetch(href).then(function (r) { return r.text(); }).then(function (html) {
        var doc = new DOMParser().parseFromString(html, 'text/html');
        var titleEl = doc.querySelector('.blog-post h1.post-title');
        if (titleEl) $(cfg.target).text(titleEl.textContent.trim());
      }).catch(function () { /* leave placeholder text as-is */ });
    });
  });

});
//

b:if.script:
//
let postResults = postPerPage;
let numOfPages = 2;
const pageOf = ["Page", "of"];
let noPage;
let currentPage;
let currentPageNo;
let postLabel;
const locationUrl = location.href;
const home_page = "/";

pageCurrentBlogger();

function startPagination(a) {
  let b = '';
  let pageNumber = parseInt(numOfPages / 2);
  if (pageNumber == numOfPages - pageNumber) { numOfPages = pageNumber * 2 + 1 }
  let pageStart = currentPageNo - pageNumber;
  if (pageStart < 1) pageStart = 1;
  let lastPageNo = parseInt(a / postResults) + 1;
  if (lastPageNo - 1 == a / postResults) lastPageNo = lastPageNo - 1;
  let pageEnd = pageStart + numOfPages - 1;
  if (pageEnd > lastPageNo) pageEnd = lastPageNo;

  b += '<span class="page-of">' + pageOf[0] + ' ' + currentPageNo + ' ' + pageOf[1] + ' ' + lastPageNo + '</span>';

  const c = parseInt(currentPageNo) - 1;
  if (currentPageNo > 1) {
    if (currentPageNo == 2) {
      if (currentPage == 'page') {
        b += '<a class="page-num page-prev" href="' + home_page + '"></a>';
      } else {
        b += '<a class="page-num page-prev" href="/search/label/' + postLabel + '?&max-results=' + postResults + '"></a>';
      }
    } else {
      if (currentPage == 'page') {
        b += '<a class="page-num page-prev" href="#" onclick="getPage(' + c + ');return false"></a>';
      } else {
        b += '<a class="page-num page-prev" href="#" onclick="getLabelPage(' + c + ');return false"></a>';
      }
    }
  }

  if (pageStart > 1) {
    if (currentPage == "page") {
      b += '<a class="page-num" href="' + home_page + '">1</a>';
    } else {
      b += '<a class="page-num" href="/search/label/' + postLabel + '?&max-results=' + postResults + '">1</a>';
    }
  }
  if (pageStart > 2) { b += '<span class="page-num page-dots">...</span>' }

  for (let d = pageStart; d <= pageEnd; d++) {
    if (currentPageNo == d) {
      b += '<span class="page-num page-active">' + d + '</span>';
    } else if (d == 1) {
      if (currentPage == 'page') {
        b += '<a class="page-num" href="' + home_page + '">1</a>';
      } else {
        b += '<a class="page-num" href="/search/label/' + postLabel + '?&max-results=' + postResults + '">1</a>';
      }
    } else {
      if (currentPage == 'page') {
        b += '<a class="page-num" href="#" onclick="getPage(' + d + ');return false">' + d + '</a>';
      } else {
        b += '<a class="page-num" href="#" onclick="getLabelPage(' + d + ');return false">' + d + '</a>';
      }
    }
  }

  if (pageEnd < lastPageNo - 1) { b += '<span class="page-num page-dots">...</span>' }
  if (pageEnd < lastPageNo) {
    if (currentPage == "page") {
      b += '<a class="page-num" href="#" onclick="getPage(' + lastPageNo + ');return false">' + lastPageNo + '</a>';
    } else {
      b += '<a class="page-num" href="#" onclick="getLabelPage(' + lastPageNo + ');return false">' + lastPageNo + '</a>';
    }
  }

  const e = parseInt(currentPageNo) + 1;
  if (currentPageNo < lastPageNo) {
    if (currentPage == 'page') {
      b += '<a class="page-num page-next" href="#" onclick="getPage(' + e + ');return false"></a>';
    } else {
      b += '<a class="page-num page-next" href="#" onclick="getLabelPage(' + e + ');return false"></a>';
    }
  }

  const f = document.getElementsByName('pageArea');
  const g = document.getElementById('blog-pager');
  for (let p = 0; p < f.length; p++) { f[p].innerHTML = b }
  if (f && f.length > 0) { b = '' }
  if (g) { g.innerHTML = b }
}

function dataFeed(a) {
  const b = a.feed;
  const c = parseInt(b.openSearch$totalResults.$t, 10);
  startPagination(c);
}

function pageCurrentBlogger() {
  const a = locationUrl;
  if (a.indexOf('/search/label/') != -1) {
    if (a.indexOf('?updated-max') != -1) {
      postLabel = a.substring(a.indexOf('/search/label/') + 14, a.indexOf('?updated-max'));
    } else {
      postLabel = a.substring(a.indexOf('/search/label/') + 14, a.indexOf('?&max'));
    }
  }
  if (a.indexOf('?q=') == -1 && a.indexOf('.html') == -1) {
    if (a.indexOf('/search/label/') == -1) {
      currentPage = 'page';
      if (locationUrl.indexOf('#PageNo=') != -1) {
        currentPageNo = locationUrl.substring(locationUrl.indexOf('#PageNo=') + 8, locationUrl.length);
      } else {
        currentPageNo = 1;
      }
      loadFeedScript(home_page + 'feeds/posts/summary?max-results=1&alt=json-in-script&callback=dataFeed');
    } else {
      currentPage = 'label';
      if (a.indexOf('&max-results=') == -1) { postResults = 20 }
      if (locationUrl.indexOf('#PageNo=') != -1) {
        currentPageNo = locationUrl.substring(locationUrl.indexOf('#PageNo=') + 8, locationUrl.length);
      } else {
        currentPageNo = 1;
      }
      loadFeedScript(home_page + 'feeds/posts/summary/-/' + postLabel + '?alt=json-in-script&callback=dataFeed&max-results=1');
    }
  }
}

function loadFeedScript(src) {
  const s = document.createElement('script');
  s.src = src;
  document.getElementsByTagName('head')[0].appendChild(s);
}

function getPage(a) {
  const jsonstart = (a - 1) * postResults;
  noPage = a;
  loadFeedScript(home_page + 'feeds/posts/summary?start-index=' + jsonstart + '&max-results=1&alt=json-in-script&callback=findPostDate');
}

function getLabelPage(a) {
  const jsonstart = (a - 1) * postResults;
  noPage = a;
  loadFeedScript(home_page + 'feeds/posts/summary/-/' + postLabel + '?start-index=' + jsonstart + '&max-results=1&alt=json-in-script&callback=findPostDate');
}

function findPostDate(a) {
  const post = a.feed.entry[0];
  const b = post.published.$t.substring(0, 19) + post.published.$t.substring(23, 29);
  const c = encodeURIComponent(b);
  let d;
  if (currentPage == 'page') {
    d = '/search?updated-max=' + c + '&max-results=' + postResults + '#PageNo=' + noPage;
  } else {
    d = '/search/label/' + postLabel + '?updated-max=' + c + '&max-results=' + postResults + '#PageNo=' + noPage;
  }
  location.href = d;
}
